/**
 * @summary Upload files (multipart)
 */
export const getUploadFilesUrl = (id: string) => {
  return `/api/projects/${id}/upload`;
};

export const uploadFiles = async (
  id: string,
  uploadFilesBody: UploadFilesBody,
  options?: RequestInit,
): Promise<UploadResult> => {
  const formData = new FormData();
  if (uploadFilesBody.files !== undefined) {
    uploadFilesBody.files.forEach((value) => formData.append(`files`, value));
  }
  if (uploadFilesBody.paths !== undefined) {
    uploadFilesBody.paths.forEach((value) => formData.append(`paths`, value));
  }
  if (uploadFilesBody.overwrite !== undefined) {
    formData.append(`overwrite`, uploadFilesBody.overwrite.toString());
  }

  return customFetch<UploadResult>(getUploadFilesUrl(id), {
    ...options,
    method: "POST",
    body: formData,
  });
};

