/**
 * @summary Revert a file to a previous version
 */
export const getRevertChangeUrl = (id: string, changeId: string) => {
  return `/api/projects/${id}/changes/${changeId}/revert`;
};

export const revertChange = async (
  id: string,
  changeId: string,
  options?: RequestInit,
): Promise<SuccessResponse> => {
  return customFetch<SuccessResponse>(getRevertChangeUrl(id, changeId), {
    ...options,
    method: "POST",
  });
};

export const getRevertChangeMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof revertChange>>,
    TError,
    { id: string; changeId: string },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof revertChange>>,
  TError,
  { id: string; changeId: string },
  TContext
> => {
  const mutationKey = ["revertChange"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof revertChange>>,
    { id: string; changeId: string }
  > = (props) => {
    const { id, changeId } = props ?? {};

    return revertChange(id, changeId, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type RevertChangeMutationResult = NonNullable<
  Awaited<ReturnType<typeof revertChange>>
>;

export type RevertChangeMutationError = ErrorType<unknown>;

/**
 * @summary Revert a file to a previous version
 */
export const useRevertChange = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof revertChange>>,
    TError,
    { id: string; changeId: string },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof revertChange>>,
  TError,
  { id: string; changeId: string },
  TContext
> => {
  return useMutation(getRevertChangeMutationOptions(options));
};

/**
 * @summary Get project preview entry point
 */
export const getGetPreviewEntryUrl = (id: string) => {
  return `/api/projects/${id}/preview-entry`;
};

export const getPreviewEntry = async (
  id: string,
  options?: RequestInit,
): Promise<PreviewEntry> => {
  return customFetch<PreviewEntry>(getGetPreviewEntryUrl(id), {
    ...options,
    method: "GET",
  });
};

export const getGetPreviewEntryQueryKey = (id: string) => {
  return [`/api/projects/${id}/preview-entry`] as const;
};

export const getGetPreviewEntryQueryOptions = <
  TData = Awaited<ReturnType<typeof getPreviewEntry>>,
  TError = ErrorType<unknown>,
>(
  id: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getPreviewEntry>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetPreviewEntryQueryKey(id);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getPreviewEntry>>> = ({
    signal,
  }) => getPreviewEntry(id, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getPreviewEntry>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

